import type { AccountingPeriodDto } from '../services/kt/models';

/** BR-014 — ngày hạch toán không thuộc kỳ Locked/Closed (MM advance-payment). */
export function validateVoucherDateAgainstPeriods(
  voucherDate: string,
  periods: AccountingPeriodDto[],
): string | null {
  if (!voucherDate || periods.length === 0) return null;
  const [yearStr, monthStr] = voucherDate.split('-');
  const year = Number(yearStr);
  const month = Number(monthStr);
  if (!year || !month) return null;

  const period = periods.find(p => p.year === year && p.month === month);
  if (period && (period.status === 'Locked' || period.status === 'Closed')) {
    return 'Không nhập/sửa chứng từ trong kỳ đã khóa hoặc đóng sổ (BR-001)';
  }
  return null;
}
