import React from 'react';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

type Props = Pick<
  TamUngFormViewModel,
  | 'validationErrors'
  | 'bannerClosed'
  | 'bannerExpanded'
  | 'setBannerExpanded'
  | 'setBannerClosed'
  | 'validationBannerId'
  | 'tid'
  | 'styles'
>;

export const TamUngValidationBanner: React.FC<Props> = ({
  validationErrors,
  bannerClosed,
  bannerExpanded,
  setBannerExpanded,
  setBannerClosed,
  validationBannerId,
  tid,
  styles: df,
}) => {
  if (validationErrors.length === 0 || bannerClosed) return null;
  return (
    <div
      id={validationBannerId}
      className={df.errorBanner}
      data-testid={validationBannerId}
      role="alert"
    >
      <div className={df.errorBannerBody}>
        <div className={df.errorBannerHeader}>
          <strong>{validationErrors.length} lỗi cần xử lý</strong>
          <div className={df.errorBannerActions}>
            <button
              type="button"
              className={df.errorBannerToggle}
              onClick={() => setBannerExpanded(v => !v)}
            >
              {bannerExpanded ? '▲ Thu gọn' : '▼ Chi tiết'}
            </button>
            <button
              type="button"
              className={df.errorBannerClose}
              onClick={() => setBannerClosed(true)}
            >
              ✕
            </button>
          </div>
        </div>
        <div
          className={[
            df.errorListCollapse,
            bannerExpanded ? df.errorListCollapseExpanded : '',
          ].filter(Boolean).join(' ')}
          aria-hidden={!bannerExpanded}
        >
          <ul className={`${df.errorList} ${df.errorListInner}`}>
            {validationErrors.map((e, i) => (
              <li key={`${i}-${e}`} data-testid={tid(`validation-error-${i}`)}>{e}</li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};
