import { useCallback, useMemo, useReducer } from 'react';
import { FormMode, initialFormMode } from '../../../../../components/form';
import { createField, setFieldValue, type IField } from '../../../../form-shared';
import {
  defaultTamUngHeader,
  TAM_UNG_DISPLAY_ONLY_KEYS,
  type TamUngHeaderKey,
} from '../types/tamUngHeader.types';
import { emptyTamUngLine, type TamUngLineModel } from '../types/tamUngLine.types';
import {
  initTamUngLineFields,
  newLineId,
  tamUngLinesFromState,
  type TamUngLineFieldState,
} from '../reducer/tamUngFieldHelpers';
type TamUngStatus = 'Draft' | 'Posted' | 'Settled';

interface TamUngFormMeta {
  status: TamUngStatus;
}

interface TamUngFormReducerState {
  header: Record<TamUngHeaderKey, IField<string>>;
  lines: TamUngLineFieldState[];
  meta: TamUngFormMeta;
  formMode: FormMode;
}

type TamUngFormAction =
  | { type: 'SET_HEADER'; key: TamUngHeaderKey; value: string }
  | { type: 'SET_LINE'; lineId: string; key: keyof TamUngLineModel; value: string | number }
  | { type: 'ADD_LINE' }
  | { type: 'REMOVE_LINE'; index: number }
  | { type: 'SET_LINES'; lines: TamUngLineFieldState[] }
  | { type: 'SET_META'; patch: Partial<TamUngFormMeta> }
  | { type: 'SET_FORM_MODE'; formMode: FormMode }
  | { type: 'RESET' };

function initHeader() {
  const model = defaultTamUngHeader();
  const out = {} as Record<TamUngHeaderKey, IField<string>>;
  (Object.keys(model) as TamUngHeaderKey[]).forEach(key => {
    out[key] = createField(model[key], { displayOnly: TAM_UNG_DISPLAY_ONLY_KEYS.includes(key) });
  });
  return out;
}

function createInitial(): TamUngFormReducerState {
  return {
    header: initHeader(),
    lines: [initTamUngLineFields(emptyTamUngLine(), newLineId())],
    meta: { status: 'Draft' },
    formMode: FormMode.Edit,
  };
}

function tamUngReducer(state: TamUngFormReducerState, action: TamUngFormAction): TamUngFormReducerState {
  switch (action.type) {
    case 'SET_HEADER': {
      const displayOnly = TAM_UNG_DISPLAY_ONLY_KEYS.includes(action.key);
      return {
        ...state,
        header: {
          ...state.header,
          [action.key]: setFieldValue(state.header[action.key], action.value, displayOnly),
        },
      };
    }
    case 'SET_LINE': {
      const idx = state.lines.findIndex(l => l.lineId === action.lineId);
      if (idx < 0) return state;
      const line = state.lines[idx];
      const field = line.fields[action.key];
      const next = [...state.lines];
      next[idx] = { ...line, fields: { ...line.fields, [action.key]: setFieldValue(field, action.value) } };
      return { ...state, lines: next };
    }
    case 'ADD_LINE':
      return { ...state, lines: [...state.lines, initTamUngLineFields(emptyTamUngLine(), newLineId())] };
    case 'REMOVE_LINE':
      if (state.lines.length <= 1) return state;
      return { ...state, lines: state.lines.filter((_, i) => i !== action.index) };
    case 'SET_LINES':
      return { ...state, lines: action.lines };
    case 'SET_META':
      return { ...state, meta: { ...state.meta, ...action.patch } };
    case 'SET_FORM_MODE':
      return { ...state, formMode: action.formMode };
    case 'RESET':
      return createInitial();
    default:
      return state;
  }
}

export function useTamUngFormState(isNew: boolean) {
  const [state, dispatch] = useReducer(
    tamUngReducer,
    { isNew },
    init => ({ ...createInitial(), formMode: initialFormMode(init.isNew) }),
  );

  const setHeader = useCallback((key: TamUngHeaderKey, value: string) => {
    dispatch({ type: 'SET_HEADER', key, value });
  }, []);

  const h = state.header;
  const bind = (key: TamUngHeaderKey) => ({
    value: h[key].value,
    set: (v: string) => setHeader(key, v),
  });

  const voucherDate = h.voucherDate.value;
  const setVoucherDate = (v: string) => setHeader('voucherDate', v);
  const createdDate = h.createdDate.value;
  const setCreatedDate = (v: string) => setHeader('createdDate', v);
  const voucherCode = h.voucherCode.value;
  const setVoucherCode = (v: string) => setHeader('voucherCode', v);
  const customerId = h.customerId.value;
  const setCustomerId = (v: string) => setHeader('customerId', v);
  const customerCode = h.customerCode.value;
  const setCustomerCode = (v: string) => setHeader('customerCode', v);
  const customerName = h.customerName.value;
  const setCustomerName = (v: string) => setHeader('customerName', v);
  const customerPhone = h.customerPhone.value;
  const setCustomerPhone = (v: string) => setHeader('customerPhone', v);
  const creditAccountCode = h.creditAccountCode.value;
  const setCreditAccountCode = (v: string) => setHeader('creditAccountCode', v);
  const creditAccountName = h.creditAccountName.value;
  const setCreditAccountName = (v: string) => setHeader('creditAccountName', v);
  const description = h.description.value;
  const setDescription = (v: string) => setHeader('description', v);
  const processingLevel = h.processingLevel.value;
  const setProcessingLevel = (v: string) => setHeader('processingLevel', v);

  const lines = useMemo(() => tamUngLinesFromState(state.lines), [state.lines]);
  const setLines = useCallback((next: TamUngLineModel[]) => {
    dispatch({
      type: 'SET_LINES',
      lines: next.length > 0
        ? next.map((m, i) => initTamUngLineFields(m, state.lines[i]?.lineId ?? newLineId()))
        : [initTamUngLineFields(emptyTamUngLine(), newLineId())],
    });
  }, [state.lines]);

  const patchLine = useCallback((idx: number, patch: Partial<TamUngLineModel>) => {
    const line = state.lines[idx];
    if (!line) return;
    (Object.keys(patch) as (keyof TamUngLineModel)[]).forEach(key => {
      if (patch[key] !== undefined) {
        dispatch({ type: 'SET_LINE', lineId: line.lineId, key, value: patch[key] as string | number });
      }
    });
  }, [state.lines]);

  return {
    state,
    dispatch,
    bind,
    voucherDate,
    setVoucherDate,
    createdDate,
    setCreatedDate,
    voucherCode,
    setVoucherCode,
    customerId,
    setCustomerId,
    customerCode,
    setCustomerCode,
    customerName,
    setCustomerName,
    customerPhone,
    setCustomerPhone,
    creditAccountCode,
    setCreditAccountCode,
    creditAccountName,
    setCreditAccountName,
    description,
    setDescription,
    processingLevel,
    setProcessingLevel,
    lines,
    setLines,
    patchLine,
    addBlankLine: () => dispatch({ type: 'ADD_LINE' }),
    removeLineAt: (index: number) => dispatch({ type: 'REMOVE_LINE', index }),
    status: state.meta.status,
    setStatus: (s: TamUngStatus) => dispatch({ type: 'SET_META', patch: { status: s } }),
    formMode: state.formMode,
    setFormMode: (m: FormMode) => dispatch({ type: 'SET_FORM_MODE', formMode: m }),
    resetForm: () => dispatch({ type: 'RESET' }),
  };
}
